let flushPending=!1,flushing=!1,queue=[],lastFlushedIndex=-1,transactionActive=!1;export function scheduler(e){queueJob(e)}export function startTransaction(){transactionActive=!0}export function commitTransaction(){transactionActive=!1,queueFlush()}function queueJob(e){queue.includes(e)||queue.push(e),queueFlush()}export function dequeueJob(e){let u=queue.indexOf(e);-1!==u&&u>lastFlushedIndex&&queue.splice(u,1)}function queueFlush(){if(!flushing&&!flushPending){if(transactionActive)return;flushPending=!0,queueMicrotask(flushJobs)}}export function flushJobs(){flushPending=!1,flushing=!0;for(let e=0;e<queue.length;e++)queue[e](),lastFlushedIndex=e;queue.length=0,lastFlushedIndex=-1,flushing=!1}